import{c as d,Q as t,j as o,m as c}from"./chunks/framework.DVkeSyfh.js";const h=JSON.parse('{"title":"Справочник Web API","description":"","frontmatter":{},"headers":[],"relativePath":"ru/api.md","filePath":"ru/api.md","lastUpdated":1781987321000}'),a={name:"ru/api.md"};function r(s,e,i,l,n,p){return t(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="справочник-web-api" tabindex="-1">Справочник Web API <a class="header-anchor" href="#справочник-web-api" aria-label="Permalink to &quot;Справочник Web API&quot;">​</a></h1><p>Эта страница документирует эндпоинты FastAPI, которые использует фронтенд. Большинству пользователей не нужно вызывать эти эндпоинты напрямую; обращайтесь к этой странице при отладке веб-интерфейса, интеграции локального скрипта или проверке того, какое серверное действие выполняет та или иная кнопка UI.</p><h2 id="справочник-web-api-1" tabindex="-1">Справочник Web API <a class="header-anchor" href="#справочник-web-api-1" aria-label="Permalink to &quot;Справочник Web API&quot;">​</a></h2><p>Фронтенд использует эти эндпоинты через <code>frontend/src/api.ts</code>.</p><p>API ориентирован на локальную работу. Эндпоинты сканирования, анализа, поиска, предпросмотра, экспорта, сброса, очистки и переноса работают с выбранной базой данных SQLite и локальными путями файловой системы. Запись в аудиофайлы происходит только через явные эндпоинты записи MAEST-жанров в теги.</p><h3 id="соглашения" tabindex="-1">Соглашения <a class="header-anchor" href="#соглашения" aria-label="Permalink to &quot;Соглашения&quot;">​</a></h3><p>Эти общие соглашения действуют для всего API:</p><table tabindex="0"><thead><tr><th>Соглашение</th><th>Описание</th></tr></thead><tbody><tr><td><code>400</code> <code>DatabaseNotSelected</code></td><td>Эндпоинт, которому нужна база данных, был вызван до того, как база была выбрана. Сначала выберите её через <code>/api/database/switch</code>.</td></tr><tr><td><code>409</code> <code>DatabaseBusy</code></td><td>Попытка переключения базы данных во время задания в состоянии <code>queued</code> или <code>running</code>. Дождитесь завершения задания или отмените его, затем повторите.</td></tr><tr><td><code>404</code></td><td>Неизвестный идентификатор трека, задания или медиа.</td></tr><tr><td>Поле <code>state</code> задания</td><td>Одно из значений <code>queued</code>, <code>running</code>, <code>completed</code>, <code>cancelled</code> или <code>failed</code>.</td></tr><tr><td>Эндпоинты заданий <code>latest</code></td><td>Возвращают <code>null</code>, если задание этого семейства ещё ни разу не запускалось.</td></tr></tbody></table><p>Длительная работа (сканирование, обновление тегов, multi-model audio analysis, оценка классификаторами, задания записи жанровых тегов) запускается через <code>POST</code>, который возвращает начальный объект статуса задания. Затем фронтенд опрашивает соответствующий эндпоинт <code>jobs/latest</code> или <code>jobs/{job_id}</code> и может запросить кооперативную отмену.</p><h3 id="база-данных" tabindex="-1">База данных <a class="header-anchor" href="#база-данных" aria-label="Permalink to &quot;База данных&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Метод</th><th>Путь</th><th>Назначение</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/database/current</code></td><td>Вернуть состояние выбранной базы данных.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/switch</code></td><td>Переключиться на путь базы данных.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/dialog</code></td><td>Открыть локальный диалог выбора базы данных.</td></tr><tr><td><code>POST</code></td><td><code>/api/database/clear</code></td><td>Очистить локальные треки SQLite, embeddings и зависимые оценки классификаторов.</td></tr></tbody></table><p>Используйте эти эндпоинты при выборе активной базы данных библиотеки. <code>clear</code> — это операция над базой данных, а не удаление аудиофайлов, но она удаляет индекс библиотеки и строки анализа из выбранного файла SQLite.</p><h3 id="библиотека" tabindex="-1">Библиотека <a class="header-anchor" href="#библиотека" aria-label="Permalink to &quot;Библиотека&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Метод</th><th>Путь</th><th>Назначение</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/library/scan</code></td><td>Запустить задание сканирования корневой папки.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/tags/refresh</code></td><td>Запустить задание обновления Mutagen-тегов.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/relocate</code></td><td>Просмотреть план или применить перенос сохранённых путей.</td></tr><tr><td><code>GET</code></td><td><code>/api/library/summary</code></td><td>Вернуть счётчики треков, семейств анализа, понравившихся треков и полного покрытия оценками продвинутых классификаторов.</td></tr><tr><td><code>GET</code></td><td><code>/api/tracks</code></td><td>Вернуть постраничную страницу треков с поиском.</td></tr><tr><td><code>GET</code></td><td><code>/api/tracks/{track_id}</code></td><td>Вернуть полные данные одного трека.</td></tr><tr><td><code>POST</code></td><td><code>/api/tracks/{track_id}/liked</code></td><td>Сохранить или снять локальный флаг «нравится» для одного трека.</td></tr><tr><td><code>POST</code></td><td><code>/api/tracks/filtered</code></td><td>Вернуть отфильтрованные строки треков для рабочих процессов выбора.</td></tr></tbody></table><p><code>/api/tracks</code> и <code>/api/tracks/filtered</code> принимают <code>preset=syncopated</code> для фильтрации по сохранённому флагу синкопированного ритма MAEST. Они принимают <code>liked=true</code>, чтобы показывать только понравившиеся треки, а карты порогов классификаторов фильтруют треки по сохранённым оценкам классификаторов.</p><p>Параметр поиска <code>q</code> по умолчанию сохраняет substring <code>LIKE</code> поведение. Передайте <code>search_mode=fts</code>, чтобы использовать явный token-based FTS5 index. FTS не ищет произвольные подстроки внутри token. Он обычно быстрее для count/narrow token matches, но paged response всё равно сортируется в library order, поэтому latency первой страницы может меняться для очень частых terms.</p><p>Используйте <code>/api/tracks</code> для постраничного просмотра, а <code>/api/tracks/{track_id}</code> — только когда диалогу с полными метаданными нужен один трек. Это сохраняет отзывчивость для больших библиотек.</p><p><code>/api/library/summary</code> включает счётчик <code>classifiers</code>. Он учитывает трек только если у трека есть сохранённые строки <code>track_classifier_scores</code> для каждого продвинутого классификатора, обнаруженного из <code>models/classifiers/*/model.json</code>.</p><p><code>/api/library/relocate</code> — это эндпоинт с предпросмотром в первую очередь: по умолчанию он возвращает план переноса и обновляет сохранённые значения <code>tracks.path</code> только при <code>apply=true</code>. У него нет кнопки в текущем веб-интерфейсе и нет метода в <code>frontend/src/api.ts</code>; управляйте переносом через CLI-команду <code>dj-sim relocate-library</code> или прямым вызовом API. Применение отклоняется при наличии конфликтов или отсутствии целевых файлов.</p><h3 id="задания" tabindex="-1">Задания <a class="header-anchor" href="#задания" aria-label="Permalink to &quot;Задания&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Метод</th><th>Путь</th><th>Назначение</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/library/scan/jobs/latest</code></td><td>Вернуть последнее задание сканирования или обновления тегов.</td></tr><tr><td><code>GET</code></td><td><code>/api/library/scan/jobs/{job_id}</code></td><td>Вернуть одно задание сканирования.</td></tr><tr><td><code>POST</code></td><td><code>/api/library/scan/jobs/{job_id}/cancel</code></td><td>Запросить отмену сканирования.</td></tr><tr><td><code>GET</code></td><td><code>/api/analysis/jobs/latest</code></td><td>Вернуть последнее multi-model audio analysis задание.</td></tr><tr><td><code>GET</code></td><td><code>/api/analysis/jobs/{job_id}</code></td><td>Вернуть одно multi-model audio analysis задание.</td></tr><tr><td><code>POST</code></td><td><code>/api/analysis/jobs/{job_id}/cancel</code></td><td>Запросить отмену multi-model analysis.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/latest</code></td><td>Вернуть последнее задание классификатора.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/{job_id}</code></td><td>Вернуть одно задание классификатора.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/{classifier_key}/analyze/jobs/{job_id}/cancel</code></td><td>Запросить отмену классификатора.</td></tr><tr><td><code>GET</code></td><td><code>/api/tags/genres/jobs/latest</code></td><td>Вернуть последнее задание записи жанровых тегов.</td></tr><tr><td><code>GET</code></td><td><code>/api/tags/genres/jobs/{job_id}</code></td><td>Вернуть одно задание записи жанровых тегов.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/jobs/{job_id}/cancel</code></td><td>Запросить отмену записи жанровых тегов.</td></tr></tbody></table><p>Эндпоинты заданий позволяют фронтенду опрашивать длительную работу и запрашивать отмену. Отмена является кооперативной: задание может завершить текущий трек или пакет, прежде чем остановиться.</p><h3 id="анализ-и-поиск" tabindex="-1">Анализ и поиск <a class="header-anchor" href="#анализ-и-поиск" aria-label="Permalink to &quot;Анализ и поиск&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Метод</th><th>Путь</th><th>Назначение</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/analysis/jobs</code></td><td>Запустить одно selected-model audio-analysis задание для SONARA, MAEST, MERT и/или CLAP.</td></tr><tr><td><code>GET</code></td><td><code>/api/classifiers</code></td><td>Список продвинутых классификаторов из <code>models/classifiers/*/model.json</code>.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/{classifier_key}/analyze</code></td><td>Запустить оценку классификатором.</td></tr><tr><td><code>POST</code></td><td><code>/api/classifiers/reset</code></td><td>Удалить сохранённые оценки для указанных ключей классификаторов.</td></tr><tr><td><code>POST</code></td><td><code>/api/analysis/reset</code></td><td>Сбросить одно семейство анализа.</td></tr><tr><td><code>POST</code></td><td><code>/api/search</code></td><td>Поиск в пространстве embedding MERT.</td></tr><tr><td><code>POST</code></td><td><code>/api/search/sonara</code></td><td>Поиск по признакам Sonara.</td></tr><tr><td><code>POST</code></td><td><code>/api/search/text</code></td><td>Поиск по аудиовекторам CLAP из текста.</td></tr><tr><td><code>POST</code></td><td><code>/api/set-builder/generate</code></td><td>Сгенерировать упорядоченный preview Smart Set Builder из manual seeds или auto anchors.</td></tr></tbody></table><p>Используйте <code>/api/analysis/jobs</code> перед эндпоинтами поиска, если библиотека ещё не обработана. Request body принимает <code>models</code>, <code>limit</code>, <code>device</code>, <code>top_k</code>, <code>track_batch_size</code> и <code>inference_batch_size</code>. <code>models</code> по умолчанию включает все четыре аудиомодели (<code>sonara</code>, <code>maest</code>, <code>mert</code>, <code>clap</code>) и должен быть непустым subset. <code>limit: null</code> означает все eligible tracks; положительные limits считают tracks, у которых отсутствует хотя бы одна выбранная модель.</p><p><code>track_batch_size</code> управляет тем, сколько декодированных треков задание держит и обрабатывает вместе. <code>inference_batch_size</code> управляет forward-pass batches MAEST/MERT/CLAP. Значения по умолчанию: <code>track_batch_size=4</code> и <code>inference_batch_size=24</code>. Старое единое поле request <code>batch_size</code> больше не принимается.</p><p>Analysis job пропускает результаты выбранных моделей, которые уже существуют. Top-level status использует <code>total</code>, <code>processed</code>, <code>analyzed</code>, <code>failed</code> и <code>skipped</code> как track-level counters. <code>model_progress</code> хранит per-model counters. Status responses отдают <code>track_batch_size</code> и <code>inference_batch_size</code>; legacy response field <code>batch_size</code> больше не выводится. <code>current_model</code> показывает, какая выбранная модель выполняется сейчас. Пустые результаты поиска часто означают, что у кандидатов отсутствуют нужные признаки Sonara, embeddings MERT или embeddings CLAP.</p><p><code>GET /api/classifiers</code> не требует базы данных; он обнаруживает продвинутые профили на диске. UI может запускать promoted classifier scoring из того же analysis control block, что и аудиомодели, через <code>CLASSIFIERS</code>; внутри это всё ещё вызывает <code>/api/classifiers/{classifier_key}/analyze</code> для каждого обнаруженного профиля после завершения выбранного audio-analysis job. Треки без нужных SONARA, MERT и MAEST inputs пропускаются classifier scoring. <code>/api/classifiers/reset</code> принимает список ключей классификаторов и удаляет их строки <code>track_classifier_scores</code> (пустой список ничего не удаляет).</p><p>Default result limit для <code>/api/search</code>, <code>/api/search/sonara</code> и <code>/api/search/text</code> равен <code>10</code>, если request не передаёт <code>limit</code>.</p><p><code>POST /api/set-builder/generate</code> — read-only endpoint для preview сета. Он не запускает audio analysis, не считает classifiers, не сохраняет sessions, не пишет теги и не меняет аудиофайлы. Он использует только сохранённые MERT, MAEST и CLAP audio embeddings, сохранённые SONARA playlist features и необязательные сохранённые promoted-classifier scores. MAEST genre labels не участвуют в выборе кандидатов.</p><p>Поля запроса:</p><ul><li><code>seed_mode</code>: <code>manual</code> или <code>auto</code>. Manual mode требует <code>1-5</code><code>seed_track_ids</code>; auto mode выбирает <code>1-5</code> связанных anchors из feature-complete tracks.</li><li><code>seed_track_ids</code>: ID manual seed-треков. В auto mode игнорируется.</li><li><code>auto_seed_count</code>: сколько связанных anchors выбрать в auto mode, <code>1-5</code>.</li><li><code>mode</code>: <code>similar_crate</code>, <code>weird_adjacent</code>, <code>balanced_set</code> или <code>discovery</code>.</li><li><code>limit</code>: длина preview, по умолчанию <code>24</code>.</li><li><code>diversity</code>: <code>0.0-1.0</code>, используется при упорядочивании.</li><li><code>energy_curve</code>: <code>warmup</code>, <code>balanced</code>, <code>peak</code> или <code>wave</code>.</li><li><code>bpm_mode</code>: <code>general</code>, <code>low_to_high</code> или <code>high_to_low</code>. <code>general</code> оставляет прежнее мягкое BPM/key transition поведение без отдельной траектории темпа.</li><li><code>bpm_change</code>: <code>slow</code>, <code>medium</code> или <code>fast</code>; используется только когда <code>bpm_mode</code> не <code>general</code>.</li><li><code>bpm_start</code>, <code>bpm_target</code>: необязательные значения <code>20-300</code> BPM для траектории темпа. Если поле пустое, builder выводит значение из первого seed/anchor и доступного BPM-диапазона библиотеки.</li><li><code>classifier_targets</code>, <code>classifier_avoid</code>: карты от promoted <code>classifier_key</code> к threshold <code>0.0-1.0</code>.</li><li><code>classifier_curves</code>: карты от promoted <code>classifier_key</code> к <code>{start, end}</code> целевым значениям intensity.</li><li><code>random_seed</code>: необязательное целое число для воспроизведения одной randomized generation. Не передавайте его, если нужен свежий случайный auto/ordering pass.</li></ul><p>Ответ включает <code>seed_track_ids</code>, счётчики покрытия признаков и ordered <code>items</code>. Каждый item содержит <code>track</code>, <code>reason</code>, <code>score</code>, <code>score_breakdown</code>, <code>sonara_groups</code>, <code>classifier_scores</code> и transition metadata. Seeds или auto anchors входят в возвращённую последовательность с <code>reason=seed_anchor</code>. В SET preview items поле <code>track.bpm</code> — это effective BPM, который использовал SET ordering: сначала file-tag BPM, затем SONARA fallback только если тег отсутствует.</p><p>Треки без обязательных MERT, MAEST, CLAP или SONARA inputs исключаются из генерации кандидатов. Отсутствующие classifier scores допустимы: они дают нейтральный вклад классификатора и более низкую classifier confidence в объяснении score. BPM/key ordering мягкий: сначала используются file tags, при их отсутствии — SONARA fallback. Если выбран явный BPM mode, фактический BPM трека дополнительно участвует в low-to-high или high-to-low tempo curve; отсутствующий BPM остаётся нейтральным, а не исключает трек. Ordered preview также соблюдает строгий artist guard: один известный исполнитель может появиться в одном preview максимум один раз. Manual seeds входят в ответ как <code>seed_anchor</code>, но повтор известного исполнителя среди manual seeds отклоняется. Auto anchors и остальные позиции семплируются из mode-scored pools, поэтому повторные вызовы без <code>random_seed</code> могут возвращать разные, но связанные сеты.</p><p>Область сброса по семействам:</p><table tabindex="0"><thead><tr><th>Сброс</th><th>Что удаляет</th></tr></thead><tbody><tr><td><code>/api/analysis/reset</code> <code>sonara</code></td><td>Ключи метаданных <code>sonara_*</code>; пересчитывает сохранённые BPM/тональность/энергию/длительность из оставшихся метаданных.</td></tr><tr><td><code>/api/analysis/reset</code> <code>maest</code></td><td>Ключи метаданных <code>maest_*</code> плюс embeddings <code>maest</code>.</td></tr><tr><td><code>/api/analysis/reset</code> <code>mert</code> / <code>clap</code></td><td>Embeddings соответствующего ключа.</td></tr><tr><td><code>/api/classifiers/reset</code></td><td>Строки <code>track_classifier_scores</code> для перечисленных ключей классификаторов.</td></tr></tbody></table><h3 id="экспорт-теги-диалоги-медиа" tabindex="-1">Экспорт, теги, диалоги, медиа <a class="header-anchor" href="#экспорт-теги-диалоги-медиа" aria-label="Permalink to &quot;Экспорт, теги, диалоги, медиа&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Метод</th><th>Путь</th><th>Назначение</th></tr></thead><tbody><tr><td><code>POST</code></td><td><code>/api/export</code></td><td>Экспортировать выбранные треки как M3U или CSV.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/apply</code></td><td>Синхронно записать MAEST-жанры во все треки, у которых есть MAEST-жанры.</td></tr><tr><td><code>POST</code></td><td><code>/api/tags/genres/jobs</code></td><td>Запустить отменяемое фоновое задание записи MAEST-жанров в теги.</td></tr><tr><td><code>POST</code></td><td><code>/api/dialog/folder</code></td><td>Открыть диалог выбора папки.</td></tr><tr><td><code>GET</code></td><td><code>/media/{track_id}</code></td><td>Отдать воспроизводимое в браузере аудио для одного трека.</td></tr></tbody></table><p>Оба эндпоинта записи жанровых тегов применяются ко всем трекам, у которых есть сохранённые MAEST-жанры. Они не принимают подмножество треков: тело запроса с <code>track_ids</code> отклоняется с HTTP <code>400</code>. Это явный путь записи в аудиофайл, и он перезаписывает только стандартное поле жанра.</p><p>Плеер предпросмотра во фронтенде использует <code>/media/{track_id}</code> и запускает воспроизведение после нажатия кнопки предпросмотра. Ответы AIFF/AIF транскодируются во временные файлы WAV для совместимости с браузером и поддержки перемотки без перезаписи исходного аудио. Если подготовка preview не удалась, например FFmpeg отклонил поврежденный файл, endpoint возвращает HTTP <code>422</code> с текстом ошибки FFmpeg вместо внутреннего traceback.</p><p>Используйте <code>/api/export</code> для файлов плейлистов и отчётов. Предпочитайте <code>/api/tags/genres/jobs</code> для записи жанров, чтобы были доступны прогресс и отмена; синхронный <code>/api/tags/genres/apply</code> возвращает по одной строке результата на трек, но блокируется до завершения всего пакета.</p>',41)])])}const m=d(a,[["render",r]]);export{h as __pageData,m as default};
